/**
 * Safe template (committed). Replace every YOUR_* below, then merge into workflow:
 *   node n8n/snippets/merge-hourly-fetch.mjs --example
 * Or copy to `hourly-fetch-with-marketing.js` (gitignored): merge prefers that file.
 *
 * Remote hourly scope: RMT + AUS, selling or training. Operations excluded.
 * Intraday: cumulative MTD from latest snapshot + rolling deltas vs prior snapshot (≈ hourly scrape cadence).
 * Marketing blend: calendar week-to-date (Mon–last completed day) when AAR rows exist; else trailing 7 days.
 */
const apikey = "YOUR_ROLI_ANON_KEY";
let base = "YOUR_ROLI_SUPABASE_URL";
base = base.replace(/\/+$/, "");

const mktApikey = "YOUR_MARKETING_AAR_ANON_KEY";
let mktBase = "YOUR_MARKETING_AAR_REST_URL";
mktBase = mktBase.replace(/\/+$/, "");

/** PostgREST base: `https://<ref>.supabase.co/rest/v1` */
function toRestV1(origin) {
  const u = origin.replace(/\/+$/, "");
  return /\/rest\/v1$/i.test(u) ? u : `${u}/rest/v1`;
}
base = toRestV1(base);
mktBase = toRestV1(mktBase);

const hdr = { apikey, Authorization: `Bearer ${apikey}` };
const hdrMkt = { apikey: mktApikey, Authorization: `Bearer ${mktApikey}` };

const now = new Date();
const centralStr = now.toLocaleDateString("en-CA", {
  timeZone: "America/Chicago",
});
const centralHour = Number(
  now.toLocaleString("en-US", {
    timeZone: "America/Chicago",
    hour: "numeric",
    hour12: false,
  })
);

/** Weekday index Sun=0..Sat=6 in America/Chicago (never parse locale strings into Date — breaks on n8n servers). */
function chicagoWeekdayShort(ms) {
  return new Intl.DateTimeFormat("en-US", {
    timeZone: "America/Chicago",
    weekday: "short",
  }).format(new Date(ms));
}

function chicagoDateString(ms) {
  return new Date(ms).toLocaleDateString("en-CA", {
    timeZone: "America/Chicago",
  });
}

/** Monday YYYY-MM-DD (Chicago) for the week containing `now`. */
let mondayStr = centralStr;
let tScan = now.getTime();
for (let i = 0; i < 8; i++) {
  if (chicagoWeekdayShort(tScan) === "Mon") {
    mondayStr = chicagoDateString(tScan);
    break;
  }
  tScan -= 24 * 60 * 60 * 1000;
}

const dowOrder = { Sun: 0, Mon: 1, Tue: 2, Wed: 3, Thu: 4, Fri: 5, Sat: 6 };
const dayOfWeek = dowOrder[chicagoWeekdayShort(now.getTime())] ?? 1;
const daysThisWeek = Math.min(dayOfWeek === 0 ? 5 : dayOfWeek, 5);

function inCoachingScope(a) {
  const st = String(a.agent_status || "selling").toLowerCase();
  return st === "selling" || st === "training";
}

function isPlaceholder(v) {
  if (v == null) return true;
  const s = String(v).trim();
  return s === "" || s.startsWith("YOUR_");
}

const mktConfigured = !isPlaceholder(mktApikey) && !isPlaceholder(mktBase);

const mktCols =
  "report_date,total_cost,cpc,total_calls,total_sales,total_premium,avg_premium,roas,marketing_acq_pct";

/** Isolated GET so a Marketing 401/RLS error does not fail the whole ROLI fetch. */
const mktGet = async (queryAfterSelect) => {
  if (!mktConfigured) return [];
  try {
    const data = await this.helpers.httpRequest({
      method: "GET",
      url: `${mktBase}/company_daily_metrics?select=${mktCols}&${queryAfterSelect}`,
      headers: hdrMkt,
      json: true,
    });
    return Array.isArray(data) ? data : [];
  } catch {
    return [];
  }
};

const DEFAULT_LEAD_COST = 60;
const DEFAULT_AVG_PREM = 1150;

function rowFromMkt(r) {
  const cpc = Number(r.cpc) || DEFAULT_LEAD_COST;
  const avgPrem = Number(r.avg_premium) || DEFAULT_AVG_PREM;
  const tCost = Number(r.total_cost) || 0;
  const tSales = Number(r.total_sales) || 0;
  const costPerSale = tSales > 0 ? Math.round(tCost / tSales) : 0;
  return {
    report_date: String(r.report_date ?? "").slice(0, 10),
    total_cost: tCost,
    cpc,
    total_calls: Number(r.total_calls) || 0,
    total_sales: tSales,
    total_premium: Number(r.total_premium) || 0,
    avg_premium: avgPrem,
    roas: Number(r.roas) || 0,
    marketing_acq_pct: Number(r.marketing_acq_pct) || 0,
    cost_per_sale: costPerSale,
  };
}

/** Mean of marketing rows; `summaryMode` documents blend (week resets Monday CST). */
function averageMarketingRows(rows, anchorDate, summaryMode) {
  if (!rows || rows.length === 0) return null;
  const norm = rows.map((r) => rowFromMkt(r));
  const dates = [
    ...new Set(norm.map((r) => String(r.report_date).slice(0, 10))),
  ].sort();
  const from = dates[0] || anchorDate;
  const to = dates[dates.length - 1] || anchorDate;
  const n = norm.length;
  const mean = (pick) => norm.reduce((s, r) => s + pick(r), 0) / n;
  const sumCost = norm.reduce((s, r) => s + r.total_cost, 0);
  const sumSales = norm.reduce((s, r) => s + r.total_sales, 0);
  const costPerSale = sumSales > 0 ? Math.round(sumCost / sumSales) : 0;
  return {
    report_date: anchorDate,
    total_cost: mean((r) => r.total_cost),
    cpc: mean((r) => r.cpc),
    total_calls: Math.round(mean((r) => r.total_calls)),
    total_sales: Math.round(mean((r) => r.total_sales)),
    total_premium: mean((r) => r.total_premium),
    avg_premium: mean((r) => r.avg_premium),
    roas: mean((r) => r.roas),
    marketing_acq_pct: mean((r) => r.marketing_acq_pct),
    cost_per_sale: costPerSale,
    summary_mode: summaryMode || "rolling_7d_intraday",
    rolling_window: { from, to, days: n, resets_monday_cst: true },
  };
}

const [
  roster,
  weeklyData,
  intradayData,
  pipelineData,
  poolData,
  weeklyPoolData,
  mktExact,
  mktWeekWtd,
  mktLast7,
] = await Promise.all([
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/agents?select=name,site,tier,manager,agent_status&is_active=eq.true`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/daily_scrape_data?select=agent_name,scrape_date,ib_leads_delivered,ob_leads_delivered,ib_sales,ob_sales,custom_sales&scrape_date=gte.${mondayStr}&scrape_date=lte.${centralStr}&order=scrape_date.asc&limit=5000`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/intraday_snapshots?select=agent_name,scrape_hour,total_dials,talk_time_minutes,ib_leads_delivered,ib_sales,ob_leads_delivered,ob_sales,ib_premium,ob_premium,custom_premium,pool_dials,pool_talk_minutes,pool_self_assigned,pool_answered,pool_long_calls&scrape_date=eq.${centralStr}&limit=5000`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/pipeline_compliance_daily?select=agent_name,past_due_follow_ups,new_leads,call_queue_count,todays_follow_ups&scrape_date=eq.${centralStr}`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/leads_pool_daily_data?select=agent_name,calls_made,talk_time_minutes,self_assigned_leads,answered_calls,long_calls,sales_made&scrape_date=eq.${centralStr}`,
    headers: hdr,
    json: true,
  }),
  this.helpers.httpRequest({
    method: "GET",
    url: `${base}/leads_pool_daily_data?select=agent_name,sales_made&scrape_date=gte.${mondayStr}&scrape_date=lte.${centralStr}`,
    headers: hdr,
    json: true,
  }),
  mktGet(`report_date=eq.${centralStr}&limit=1`),
  mktGet(
    `report_date=gte.${mondayStr}&report_date=lt.${centralStr}&order=report_date.asc`
  ),
  mktGet(`report_date=lt.${centralStr}&order=report_date.desc&limit=7`),
]);

const mktTodayEq = Array.isArray(mktExact) && mktExact[0] ? mktExact[0] : null;
let mktRow = mktTodayEq;
if (!mktRow && mktConfigured) {
  const mktLatest = await mktGet("order=report_date.desc&limit=1");
  mktRow = mktLatest[0] || null;
}

const weekRows = Array.isArray(mktWeekWtd) ? mktWeekWtd : [];
const last7 = Array.isArray(mktLast7) ? mktLast7 : [];
const useWeekBlend = weekRows.length > 0;
const blended = averageMarketingRows(
  useWeekBlend ? weekRows : last7,
  centralStr,
  useWeekBlend ? "week_to_date_cst" : "rolling_7d_fallback"
);

let marketingDaily = null;
let leadCostOverride = DEFAULT_LEAD_COST;
let avgPremiumOverride = DEFAULT_AVG_PREM;

if (blended) {
  marketingDaily = blended;
  leadCostOverride = Math.round(blended.cpc);
  avgPremiumOverride = Math.round(blended.avg_premium);
} else if (mktRow) {
  marketingDaily = rowFromMkt(mktRow);
  leadCostOverride = Math.round(marketingDaily.cpc);
  avgPremiumOverride = Math.round(marketingDaily.avg_premium);
}

if (mktTodayEq) {
  const todayBody = rowFromMkt(mktTodayEq);
  try {
    await this.helpers.httpRequest({
      method: "POST",
      url: `${base}/daily_marketing_summary?on_conflict=report_date`,
      headers: {
        ...hdr,
        "Content-Type": "application/json",
        Prefer: "resolution=merge-duplicates",
      },
      body: todayBody,
      json: true,
    });
  } catch (syncErr) {
    // Table may not exist yet or RLS — workflow continues
  }
}

if (!roster || roster.length === 0) {
  throw new Error("No active agents found");
}

const rosterMap = {};
for (const a of roster) rosterMap[a.name] = a;

const weeklyByAgent = {};
for (const r of weeklyData || []) {
  if (!rosterMap[r.agent_name]) continue;
  if (!weeklyByAgent[r.agent_name]) weeklyByAgent[r.agent_name] = [];
  weeklyByAgent[r.agent_name].push({
    date: r.scrape_date,
    ibLeads: r.ib_leads_delivered || 0,
    obLeads: r.ob_leads_delivered || 0,
    ibSales: r.ib_sales || 0,
    obSales: r.ob_sales || 0,
    customSales: r.custom_sales || 0,
  });
}

const weeklyPoolSales = {};
for (const r of weeklyPoolData || []) {
  if (!rosterMap[r.agent_name]) continue;
  weeklyPoolSales[r.agent_name] =
    (weeklyPoolSales[r.agent_name] || 0) + (r.sales_made || 0);
}

function num(x) {
  return Number(x) || 0;
}

/** Latest snapshot at or before `maxHour`, vs prior snapshot — rolling production between scrapes (~1h). */
function buildIntradayRolling(rows, maxHour) {
  const sorted = [...rows].sort(
    (a, b) => Number(a.scrape_hour) - Number(b.scrape_hour)
  );
  const upTo = sorted.filter((r) => Number(r.scrape_hour) <= maxHour);
  const latest =
    upTo.length > 0 ? upTo[upTo.length - 1] : sorted[sorted.length - 1];
  if (!latest) return null;
  const prior = upTo.length >= 2 ? upTo[upTo.length - 2] : null;
  /** Only defined when two snapshots exist — otherwise cumulative would fake a "rolling hour". */
  const roll = (k) =>
    prior ? Math.max(0, num(latest[k]) - num(prior[k])) : null;
  return {
    scrape_hour: latest.scrape_hour,
    total_dials: num(latest.total_dials),
    talk_time_minutes: num(latest.talk_time_minutes),
    ib_leads_delivered: num(latest.ib_leads_delivered),
    ob_leads_delivered: num(latest.ob_leads_delivered),
    ib_sales: num(latest.ib_sales),
    ob_sales: num(latest.ob_sales),
    custom_sales: num(latest.custom_sales),
    ib_premium: num(latest.ib_premium),
    ob_premium: num(latest.ob_premium),
    custom_premium: num(latest.custom_premium),
    pool_dials: num(latest.pool_dials),
    pool_talk_minutes: num(latest.pool_talk_minutes),
    pool_self_assigned: num(latest.pool_self_assigned),
    pool_answered: num(latest.pool_answered),
    pool_long_calls: num(latest.pool_long_calls),
    rolling_anchor_hour: maxHour,
    rolling_prior_hour: prior ? prior.scrape_hour : null,
    rolling_hour_dials: roll("total_dials"),
    rolling_hour_talk_min: roll("talk_time_minutes"),
    rolling_hour_pool_dials: roll("pool_dials"),
    rolling_hour_pool_talk_min: roll("pool_talk_minutes"),
    rolling_hour_pool_self: roll("pool_self_assigned"),
    rolling_hour_pool_answered: roll("pool_answered"),
    rolling_hour_pool_long: roll("pool_long_calls"),
    rolling_hour_ib_leads: roll("ib_leads_delivered"),
    rolling_hour_ob_leads: roll("ob_leads_delivered"),
    rolling_hour_ib_sales: roll("ib_sales"),
    rolling_hour_ob_sales: roll("ob_sales"),
    rolling_hour_custom_sales: roll("custom_sales"),
  };
}

const intradayByAgent = {};
for (const r of intradayData || []) {
  if (!rosterMap[r.agent_name]) continue;
  if (!intradayByAgent[r.agent_name]) intradayByAgent[r.agent_name] = [];
  intradayByAgent[r.agent_name].push(r);
}

const intradayMap = {};
for (const name of Object.keys(rosterMap)) {
  const rows = intradayByAgent[name];
  intradayMap[name] =
    rows && rows.length ? buildIntradayRolling(rows, centralHour) : null;
}

const pipeMap = {};
for (const r of pipelineData || []) {
  if (rosterMap[r.agent_name]) pipeMap[r.agent_name] = r;
}

const poolMapData = {};
for (const r of poolData || []) {
  if (rosterMap[r.agent_name]) poolMapData[r.agent_name] = r;
}

const coachingFiltered = roster.filter(inCoachingScope);

return [
  {
    json: {
      scrapeDate: centralStr,
      centralHour,
      mondayStr,
      daysThisWeek,
      rosterMap,
      weeklyByAgent,
      weeklyPoolSales,
      intradayMap,
      pipeMap,
      poolMapData,
      orgAgentCount: roster.length,
      agentCount: coachingFiltered.length,
      marketingDaily,
      leadCostOverride,
      avgPremiumOverride,
    },
  },
];

const {
  scrapeDate,
  centralHour,
  daysThisWeek,
  rosterMap,
  weeklyByAgent,
  weeklyPoolSales,
  intradayMap,
  pipeMap,
  poolMapData,
  agentCount,
  orgAgentCount,
  leadCostOverride,
  avgPremiumOverride,
} = $input.first().json;

function inCoachingScope(a) {
  const st = String(a.agent_status || "selling").toLowerCase();
  return st === "selling" || st === "training";
}

const DEFAULT_LC = 60;
const lc =
  typeof leadCostOverride === "number" && leadCostOverride > 0 ? leadCostOverride : DEFAULT_LC;

const CFG = {
  DAILY_LEADS: 7,
  LEAD_COST: lc,
  CR_TARGET: 22,
  CR_FLOOR: 20,
  CR_CRISIS: 15,
  CR_CRISIS_DAYS: 3,
  MAX_PIPELINE: 30,
  PIPELINE_CRITICAL: 40,
  POOL_DAILY_ASSIGNS: 5,
  POOL_WEEKLY_SALES: 1,
  POOL_MIN_ASSIGN_RATE: 30,
  AVG_PREMIUM_ORG:
    typeof avgPremiumOverride === "number" && avgPremiumOverride > 0 ? avgPremiumOverride : 1150,
};

function computeWeeklyCR(rows) {
  if (!rows || rows.length === 0)
    return { weeklyCR: null, dailyCRs: [], weekLeads: 0, weekSales: 0 };
  const dailyCRs = rows.map((r) => {
    const leads = r.ibLeads + r.obLeads;
    const sales = r.ibSales + r.obSales + r.customSales;
    return leads > 0 ? (sales / leads) * 100 : 0;
  });
  const totalLeads = rows.reduce((s, r) => s + r.ibLeads + r.obLeads, 0);
  const totalSales = rows.reduce(
    (s, r) => s + r.ibSales + r.obSales + r.customSales,
    0
  );
  return {
    weeklyCR: totalLeads > 0 ? (totalSales / totalLeads) * 100 : null,
    dailyCRs,
    weekLeads: totalLeads,
    weekSales: totalSales,
  };
}

function consLow(dailyCRs, threshold) {
  let c = 0;
  for (let i = dailyCRs.length - 1; i >= 0; i--) {
    if (dailyCRs[i] < threshold) c++;
    else break;
  }
  return c;
}

function recommend(
  weeklyCR,
  dailyCRs,
  weekLeads,
  weekSales,
  pipe,
  intra,
  pool,
  poolWeekSales,
  pace
) {
  const pastDue = pipe?.past_due_follow_ups ?? 0;
  const pipeSize =
    (pipe?.new_leads ?? 0) + (pipe?.todays_follow_ups ?? 0) + pastDue;
  const poolAssigns = pool?.self_assigned_leads ?? 0;
  const poolAnswered = pool?.answered_calls ?? 0;
  const assignRate =
    poolAnswered > 0 ? (poolAssigns / poolAnswered) * 100 : 0;
  const consLowDays = consLow(dailyCRs, CFG.CR_CRISIS);
  const isMidDay = centralHour >= 12;
  const weekSpend = weekLeads * CFG.LEAD_COST;

  if (pastDue > 3)
    return {
      action: "WORK_FOLLOWUPS",
      severity: "critical",
      reason: `${pastDue} past due follow-ups. $${pastDue * CFG.LEAD_COST} in paid leads aging out. Clear these before anything else.`,
    };

  if (pipeSize > CFG.PIPELINE_CRITICAL)
    return {
      action: "CLEAR_PIPELINE",
      severity: "critical",
      reason: `Pipeline at ${pipeSize} leads (limit: ${CFG.PIPELINE_CRITICAL}). Leads are rotting. Close, withdraw, or reschedule — no new activity until pipeline is under control.`,
    };

  if (consLowDays >= CFG.CR_CRISIS_DAYS && weeklyCR !== null)
    return {
      action: "REVIEW_QUALITY",
      severity: "critical",
      reason: `CR below ${CFG.CR_CRISIS}% for ${consLowDays} straight days (week: ${weeklyCR.toFixed(0)}%). ${weekLeads} leads at $${CFG.LEAD_COST}/lead = $${weekSpend} spent, ${weekSales} closed. Manager: audit calls and coach close technique.`,
    };

  if (pastDue > 0)
    return {
      action: "WORK_FOLLOWUPS",
      severity: "warning",
      reason: `${pastDue} past due follow-up${pastDue > 1 ? "s" : ""}. These are paid leads — work them before taking pool or inbound.`,
    };

  if (pipeSize > CFG.MAX_PIPELINE)
    return {
      action: "CLEAR_PIPELINE",
      severity: "warning",
      reason: `Pipeline at ${pipeSize} leads (max: ${CFG.MAX_PIPELINE}). Close out or withdraw stale leads before adding more.`,
    };

  if (weeklyCR !== null && weeklyCR < CFG.CR_FLOOR)
    return {
      action: "FOCUS_PIPELINE",
      severity: "warning",
      reason: `CR at ${weeklyCR.toFixed(0)}% — floor is ${CFG.CR_FLOOR}%. ${weekLeads} leads, ${weekSales} sales, $${weekSpend} spent. Review call quality and close technique before taking more leads.`,
    };

  const rhDials = pace?.rollingHourDials;
  const med = pace?.teamMedianRollingDials ?? 0;
  const pipeClean = pastDue === 0 && pipeSize <= 20;
  if (
    pipeClean &&
    typeof rhDials === "number" &&
    centralHour >= 10 &&
    centralHour <= 17 &&
    med >= 10 &&
    rhDials < med * 0.35
  )
    return {
      action: "PICK_UP_PACE",
      severity: "warning",
      reason: `${rhDials} dials last hour vs team median ~${Math.round(med)}. Pipeline is clean — maintain steady calling cadence.`,
    };

  if (isMidDay && poolAssigns < 3)
    return {
      action: "GET_IN_POOL",
      severity: "warning",
      reason: `${poolAssigns} pool self-assigns (need ${CFG.POOL_DAILY_ASSIGNS}). Get in pool and find 5 people to follow up with tomorrow.`,
    };

  if (poolAnswered >= 10 && assignRate < CFG.POOL_MIN_ASSIGN_RATE)
    return {
      action: "GET_IN_POOL",
      severity: "warning",
      reason: `Pool assign rate ${assignRate.toFixed(0)}% (min: ${CFG.POOL_MIN_ASSIGN_RATE}%). Self-assign every answered contact to clean the pool.`,
    };

  if (weeklyCR !== null && weeklyCR >= CFG.CR_TARGET && pipeSize <= 20 && pastDue === 0)
    return {
      action: "TAKE_MORE_LEADS",
      severity: "info",
      reason: `CR at ${weeklyCR.toFixed(0)}% with clean pipeline (${pipeSize}). Ready for additional volume.`,
    };

  if (
    weeklyCR !== null &&
    weeklyCR >= CFG.CR_FLOOR &&
    pipeSize >= 10 &&
    pipeSize <= CFG.MAX_PIPELINE
  )
    return {
      action: "STAY_IN_QUEUE",
      severity: "info",
      reason: `CR at ${weeklyCR.toFixed(0)}% · pipeline ${pipeSize}. Keep working inbound. ${
        CFG.CR_TARGET - weeklyCR > 0
          ? (CFG.CR_TARGET - weeklyCR).toFixed(0) + "% to bonus-lead eligibility."
          : "At target."
      }`,
    };

  if (
    poolAssigns < CFG.POOL_DAILY_ASSIGNS &&
    poolWeekSales < CFG.POOL_WEEKLY_SALES &&
    pipeSize < 10
  )
    return {
      action: "GET_IN_POOL",
      severity: "info",
      reason: `Pipeline light (${pipeSize}). Get in pool — find 5 contacts to follow up with tomorrow. ${poolAssigns}/${CFG.POOL_DAILY_ASSIGNS} assigns done.`,
    };

  const parts = [];
  if (weeklyCR !== null) parts.push(`CR ${weeklyCR.toFixed(0)}%`);
  parts.push(`Pipeline ${pipeSize}`);
  if (poolAssigns > 0) parts.push(`Pool ${poolAssigns} assigns`);
  if (poolWeekSales > 0) parts.push(`Pool ${poolWeekSales} sales this week`);
  return {
    action: "ON_TRACK",
    severity: "info",
    reason: parts.join(" · ") + " — on track.",
  };
}

const scopeNames = [];
for (const [name, agent] of Object.entries(rosterMap)) {
  if (inCoachingScope(agent)) scopeNames.push(name);
}

const rollingForMedian = [];
for (const name of scopeNames) {
  const intra = intradayMap[name];
  const rd = intra?.rolling_hour_dials;
  if (typeof rd === "number") rollingForMedian.push(rd);
}
rollingForMedian.sort((a, b) => a - b);
const teamMedianRollingDials = rollingForMedian.length
  ? rollingForMedian[Math.floor(rollingForMedian.length / 2)]
  : 0;

const results = [];
for (const name of scopeNames) {
  const agent = rosterMap[name];
  const weekRows = weeklyByAgent[name] || [];
  const { weeklyCR, dailyCRs, weekLeads, weekSales } = computeWeeklyCR(weekRows);
  const pipe = pipeMap[name];
  const pool = poolMapData[name];
  const intra = intradayMap[name];
  const poolWeekSales = weeklyPoolSales[name] || 0;

  const poolSelfAssigned = pool?.self_assigned_leads ?? 0;
  const poolAnswered = pool?.answered_calls ?? 0;
  const poolDials = pool?.calls_made ?? 0;
  const poolLongCalls = pool?.long_calls ?? 0;
  const totalDials = intra?.total_dials ?? 0;
  const todaysLeads =
    (intra?.ib_leads_delivered ?? 0) + (intra?.ob_leads_delivered ?? 0);
  const todaysSales =
    (intra?.ib_sales ?? 0) + (intra?.ob_sales ?? 0) + (intra?.custom_sales ?? 0);
  const todaysCR =
    todaysLeads > 0 ? (todaysSales / todaysLeads) * 100 : null;
  const todaysPremium =
    (intra?.ib_premium ?? 0) +
    (intra?.ob_premium ?? 0) +
    (intra?.custom_premium ?? 0);
  const pastDue = pipe?.past_due_follow_ups ?? 0;
  const pipeSize = pipe
    ? (pipe.new_leads ?? 0) + (pipe.todays_follow_ups ?? 0) + pastDue
    : null;

  const rollingHourDials = intra?.rolling_hour_dials ?? null;
  const rollingHourTalkMin = intra?.rolling_hour_talk_min ?? null;
  const rollingHourPoolDials = intra?.rolling_hour_pool_dials ?? null;

  const rec = recommend(
    weeklyCR,
    dailyCRs,
    weekLeads,
    weekSales,
    pipe,
    intra,
    pool,
    poolWeekSales,
    {
      rollingHourDials,
      teamMedianRollingDials,
      centralHour,
    }
  );

  const todayLeadSpend = todaysLeads * lc;
  const costPerSale = todaysSales > 0 ? Math.round(todayLeadSpend / todaysSales) : null;
  const weekLeadSpend = weekLeads * lc;
  const weekCostPerSale = weekSales > 0 ? Math.round(weekLeadSpend / weekSales) : null;

  results.push({
    name,
    site: agent.site,
    manager: agent.manager || null,
    ...rec,
    weeklyCR: weeklyCR !== null ? Math.round(weeklyCR * 10) / 10 : null,
    weekLeads,
    weekSales,
    todaysCR: todaysCR !== null ? Math.round(todaysCR * 10) / 10 : null,
    todaysLeads,
    todaysSales,
    todaysPremium: Math.round(todaysPremium),
    todaysDials: totalDials,
    todaysTalkMin: Math.round(intra?.talk_time_minutes ?? 0),
    rollingHourDials,
    rollingHourTalkMin,
    rollingHourPoolDials,
    rollingPriorHour: intra?.rolling_prior_hour ?? null,
    pastDue,
    pipelineSize: pipeSize,
    poolDials,
    poolSelfAssigned,
    poolAnswered,
    poolLongCalls,
    poolWeekSales,
    poolOnTrack: poolWeekSales >= CFG.POOL_WEEKLY_SALES,
    teamMedianRollingDials,
    todayLeadSpend,
    costPerSale,
    weekLeadSpend,
    weekCostPerSale,
  });
}

const sev = { critical: 0, warning: 1, info: 2 };
results.sort((a, b) => sev[a.severity] - sev[b.severity]);

function compareAlertUrgency(a, b) {
  const pda = a.pastDue ?? 0;
  const pdb = b.pastDue ?? 0;
  if (pdb !== pda) return pdb - pda;
  const pia = a.pipelineSize ?? 0;
  const pib = b.pipelineSize ?? 0;
  if (pib !== pia) return pib - pia;
  const cra = a.weeklyCR ?? 999;
  const crb = b.weeklyCR ?? 999;
  return cra - crb;
}
const critical = results
  .filter((r) => r.severity === "critical")
  .sort(compareAlertUrgency);
const warning = results
  .filter((r) => r.severity === "warning")
  .sort(compareAlertUrgency);
const onTrack = results
  .filter((r) => r.severity === "info")
  .sort((a, b) => {
    const ca = a.weeklyCR ?? -1;
    const cb = b.weeklyCR ?? -1;
    if (cb !== ca) return cb - ca;
    return a.name.localeCompare(b.name);
  });

return [
  {
    json: {
      scrapeDate,
      centralHour,
      agentCount,
      orgAgentCount:
        typeof orgAgentCount === "number" ? orgAgentCount : agentCount,
      daysThisWeek,
      critical,
      warning,
      onTrack,
      results,
      cfg: CFG,
      teamMedianRollingDials,
    },
  },
];

const {
  scrapeDate,
  centralHour,
  critical,
  warning,
  onTrack,
  agentCount,
  orgAgentCount,
  daysThisWeek,
  cfg,
  teamMedianRollingDials,
} = $input.first().json;

const orgN = typeof orgAgentCount === "number" ? orgAgentCount : agentCount;
const inScopeN = agentCount;

const [y, mo, d] = scrapeDate.split("-");
const dt = new Date(+y, +mo - 1, +d);
const dn = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"][dt.getDay()];
const mn = [
  "Jan",
  "Feb",
  "Mar",
  "Apr",
  "May",
  "Jun",
  "Jul",
  "Aug",
  "Sep",
  "Oct",
  "Nov",
  "Dec",
][dt.getMonth()];
const dd = `${dn} ${mn} ${+d}, ${y}`;
const ampm =
  centralHour > 12
    ? `${centralHour - 12}:05 PM`
    : centralHour === 12
      ? "12:05 PM"
      : `${centralHour}:05 AM`;

/** Plain labels — readable in a mixed audience channel. */
const ACTION_LABEL = {
  TAKE_MORE_LEADS: "Take more leads",
  WORK_FOLLOWUPS: "Work follow-ups",
  GET_IN_POOL: "Get in pool",
  CLEAR_PIPELINE: "Clear pipeline",
  REVIEW_QUALITY: "Review call quality",
  FOCUS_PIPELINE: "Focus pipeline",
  STAY_IN_QUEUE: "Stay in queue",
  PICK_UP_PACE: "Pick up pace",
  ON_TRACK: "On track",
};

const fmt = (n) => "$" + Math.round(n).toLocaleString();

const blocks = [];

blocks.push({
  type: "header",
    text: {
    type: "plain_text",
    text: `ROLI — Hourly coaching — ${dd}`,
  },
});

blocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: [
      `*When:* ${ampm} Central`,
      `*Scope:* ${inScopeN} active agents (operations excluded). Org roster: ${orgN}.`,
      `*Week progress:* weekday ${daysThisWeek} of 5 (Mon–Fri).`,
      `*Team pace (last CRM interval):* ${
        teamMedianRollingDials != null ? `${teamMedianRollingDials} dials (median)` : "not enough snapshots yet"
      }`,
      `*This run:* ${critical.length} critical · ${warning.length} warning · ${onTrack.length} on track`,
    ].join("\n"),
  },
});

blocks.push({ type: "divider" });

function formatAgent(a, stackIdx) {
  const action = ACTION_LABEL[a.action] || String(a.action || "").replace(/_/g, " ");
  const rank = typeof stackIdx === "number" ? `#${stackIdx} ` : "";
  const lines = [
    `*${rank}${a.name}*`,
    `*Focus:* ${action}`,
    `Today (cumulative): ${a.todaysDials} dials · ${a.todaysTalkMin} min talk`,
  ];
  if (typeof a.rollingHourDials === "number") {
    lines.push(
      `Since prior snapshot: +${a.rollingHourDials} dials · +${Math.round(a.rollingHourTalkMin || 0)} min talk`
    );
  }
  if (a.todaysCR !== null) {
    lines.push(`Inbound today: ${a.todaysSales}/${a.todaysLeads} leads → ${a.todaysCR}% CR`);
  } else if (a.todaysLeads > 0) {
    lines.push(`Inbound today: ${a.todaysSales}/${a.todaysLeads} leads`);
  } else {
    lines.push(`Inbound today: no intraday row yet`);
  }
  if (a.weeklyCR !== null) {
    lines.push(`Week to date: ${a.weeklyCR}% CR (${a.weekSales} sales / ${a.weekLeads} leads)`);
  } else {
    lines.push(`Week to date: not enough closed days yet`);
  }
  if (a.pipelineSize !== null) {
    lines.push(
      `Pipeline: ${a.pipelineSize} leads` + (a.pastDue ? ` (${a.pastDue} past due)` : "")
    );
  }
  if (a.poolDials > 0) {
    lines.push(
      `Pool today: ${a.poolDials} dials · ${a.poolSelfAssigned} self-assigns · ${a.poolAnswered} answered`
    );
  }
  lines.push(`Pool week: ${a.poolWeekSales}/${cfg.POOL_WEEKLY_SALES} sales (weekly target)`);
  if (a.todaysPremium > 0) lines.push(`Premium today: ${fmt(a.todaysPremium)}`);
  if (a.costPerSale != null) {
    lines.push(`Cost/sale: ${fmt(a.costPerSale)} today` + (a.weekCostPerSale != null ? ` · ${fmt(a.weekCostPerSale)} week` : ""));
  } else if (a.todaysLeads > 0 && a.todayLeadSpend > 0) {
    lines.push(`Lead spend: ${fmt(a.todayLeadSpend)} today (0 sales)`);
  }
  lines.push(`${a.reason}`);
  return lines.join("\n");
}

if (critical.length > 0) {
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `*Critical — ${critical.length}*` },
  });
  for (let ri = 0; ri < critical.length && ri < 15; ri++) {
    blocks.push({
      type: "section",
      text: { type: "mrkdwn", text: formatAgent(critical[ri], ri + 1) },
    });
  }
  if (critical.length > 15) {
    blocks.push({
      type: "context",
      elements: [
        { type: "mrkdwn", text: `…and ${critical.length - 15} more (see ROLI for full list).` },
      ],
    });
  }
  blocks.push({ type: "divider" });
}

if (warning.length > 0) {
  blocks.push({
    type: "section",
    text: { type: "mrkdwn", text: `*Needs attention — ${warning.length}*` },
  });
  for (let ri = 0; ri < warning.length && ri < 15; ri++) {
    blocks.push({
      type: "section",
      text: { type: "mrkdwn", text: formatAgent(warning[ri], ri + 1) },
    });
  }
  if (warning.length > 15) {
    blocks.push({
      type: "context",
      elements: [
        { type: "mrkdwn", text: `…and ${warning.length - 15} more (see ROLI for full list).` },
      ],
    });
  }
  blocks.push({ type: "divider" });
}

const MAX_ON_TRACK_NAMES = 18;
if (onTrack.length > 0) {
  const names = onTrack.map((a) => a.name);
  const shown = names.slice(0, MAX_ON_TRACK_NAMES).join(", ");
  const extra =
    names.length > MAX_ON_TRACK_NAMES
      ? `\n_${names.length - MAX_ON_TRACK_NAMES} others on track — open ROLI for names._`
      : "";
  blocks.push({
    type: "section",
    text: {
      type: "mrkdwn",
      text: `*On track — ${onTrack.length}*\n${shown}${extra}`,
    },
  });
  blocks.push({ type: "divider" });
}

const allAgents = [...critical, ...warning, ...onTrack];
const totalPoolSales = allAgents.reduce((s, a) => s + a.poolWeekSales, 0);
const totalPoolAssigns = allAgents.reduce((s, a) => s + a.poolSelfAssigned, 0);
const totalPoolDials = allAgents.reduce((s, a) => s + a.poolDials, 0);
const agentsInPool = allAgents.filter((a) => a.poolDials > 0).length;
const agentsPoolGoalMet = allAgents.filter((a) => a.poolOnTrack).length;

blocks.push({
  type: "section",
  text: {
    type: "mrkdwn",
    text: [
      `*Pool snapshot (this digest)*`,
      `${agentsInPool} agents dialed pool today · ${totalPoolDials} pool dials · ${totalPoolAssigns} self-assigns`,
      `${totalPoolSales} pool sales this week · ${agentsPoolGoalMet}/${inScopeN} at weekly pool-sales target (${cfg.POOL_WEEKLY_SALES}/wk)`,
    ].join("\n"),
  },
});

blocks.push({
  type: "context",
  elements: [
    {
      type: "mrkdwn",
      text: `Targets: CR ${cfg.CR_TARGET}%+ · pipeline ≤${cfg.MAX_PIPELINE} · pool ${cfg.POOL_DAILY_ASSIGNS} assigns/day & ${cfg.POOL_WEEKLY_SALES} sale/wk · past due 0 · CPC $${cfg.LEAD_COST} · org avg premium $${cfg.AVG_PREMIUM_ORG}`,
    },
  ],
});

const fallback = `ROLI hourly — ${dd} ${ampm}: ${critical.length} critical, ${warning.length} warning, ${onTrack.length} on track`;

return [{ json: { text: fallback, blocks } }];

return [{ json: {
  text: ':x: *Hourly Action Alert failed*\n' + ($input.first().json.error || $input.first().json.message || 'Unknown error — check n8n execution log.')
} }];
